import{_ as a,o as t,c as i,aA as n}from"./chunks/framework.D0lAMIOx.js";const h=JSON.parse('{"title":"Feasibility: Generating Julia Types from Nickel Contracts","description":"","frontmatter":{},"headers":[],"relativePath":"notes/type-generation-feasibility.md","filePath":"notes/type-generation-feasibility.md","lastUpdated":null}'),s={name:"notes/type-generation-feasibility.md"};function o(l,e,r,c,p,d){return t(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="Feasibility:-Generating-Julia-Types-from-Nickel-Contracts" tabindex="-1">Feasibility: Generating Julia Types from Nickel Contracts <a class="header-anchor" href="#Feasibility:-Generating-Julia-Types-from-Nickel-Contracts" aria-label="Permalink to &quot;Feasibility: Generating Julia Types from Nickel Contracts {#Feasibility:-Generating-Julia-Types-from-Nickel-Contracts}&quot;">​</a></h1><p><strong>Status:</strong> Speculative / not planned <strong>Date:</strong> 2026-03-17</p><h2 id="Motivation" tabindex="-1">Motivation <a class="header-anchor" href="#Motivation" aria-label="Permalink to &quot;Motivation {#Motivation}&quot;">​</a></h2><p>Nickel has a rich type system including enum types (<code>[| &#39;active, &#39;inactive |]</code>), record contracts, and algebraic data types. It would be valuable to use Nickel as a schema language — define types in <code>.ncl</code> files and generate corresponding Julia structs and enums from them, enabling type-safe dispatch and validation on the Julia side.</p><p>Envisioned usage:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@nickel_types</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;schema.ncl&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># generates StatusEnum, MyConfig, etc. as Julia types</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> process</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(s</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">StatusEnum</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> end</span></span></code></pre></div><h2 id="Current-State" tabindex="-1">Current State <a class="header-anchor" href="#Current-State" aria-label="Permalink to &quot;Current State {#Current-State}&quot;">​</a></h2><h3 id="What-works-today" tabindex="-1">What works today <a class="header-anchor" href="#What-works-today" aria-label="Permalink to &quot;What works today {#What-works-today}&quot;">​</a></h3><ul><li><p>Enum <strong>values</strong> (<code>&#39;Foo</code>, <code>&#39;Some 42</code>) are fully supported via the binary protocol (TYPE_ENUM, tag 7)</p></li><li><p>They decode to <code>NickelEnum(tag::Symbol, arg::Any)</code> on the Julia side</p></li><li><p>Enum values constrained by enum types evaluate correctly: <code>nickel_eval_native(&quot;let x : [| &#39;a, &#39;b |] = &#39;a in x&quot;)</code> returns <code>NickelEnum(:a, nothing)</code></p></li></ul><h3 id="What-doesn&#39;t-exist" tabindex="-1">What doesn&#39;t exist <a class="header-anchor" href="#What-doesn&#39;t-exist" aria-label="Permalink to &quot;What doesn&amp;#39;t exist {#What-doesn&#39;t-exist}&quot;">​</a></h3><ul><li><p>No way to extract <strong>type definitions</strong> themselves through the FFI</p></li><li><p><code>eval_full_for_export()</code> produces values, not types — type information is erased during evaluation</p></li><li><p><code>nickel-lang-core 0.9.1</code> does not expose a public API for type introspection</p></li><li><p>Nickel has no runtime reflection on types — you can&#39;t ask an enum type for its list of variants</p></li></ul><h2 id="Nickel-Type-System-Background" tabindex="-1">Nickel Type System Background <a class="header-anchor" href="#Nickel-Type-System-Background" aria-label="Permalink to &quot;Nickel Type System Background {#Nickel-Type-System-Background}&quot;">​</a></h2><ul><li><p>Enum type syntax: <code>[| &#39;Carnitas, &#39;Fish |]</code> (simple), <code>[| &#39;Ok Number, &#39;Err String |]</code> (with payloads)</p></li><li><p>Enum types are structural and compile-time — they exist for the typechecker, not at runtime</p></li><li><p>Types and contracts are interchangeable: <code>foo : T</code> and <code>foo | T</code> both enforce at runtime</p></li><li><p>Row polymorphism allows extensible enums: <code>[| &#39;Ok a ; tail |]</code></p></li><li><p><code>std.enum.to_tag_and_arg</code> decomposes enum values at runtime, but cannot inspect enum types</p></li><li><p>ADTs (enum variants with data) fully supported since Nickel 1.5</p></li></ul><p>Internally, <code>nickel-lang-core</code> represents types via the <code>TypeF</code> enum, which includes <code>TypeF::Enum(row_type)</code> for enum types. But this is internal API, not a stable public surface.</p><h2 id="Approaches-Considered" tabindex="-1">Approaches Considered <a class="header-anchor" href="#Approaches-Considered" aria-label="Permalink to &quot;Approaches Considered {#Approaches-Considered}&quot;">​</a></h2><h3 id="Approach-1:-Convention-based-schema-as-value" tabindex="-1">Approach 1: Convention-based (schema as value) <a class="header-anchor" href="#Approach-1:-Convention-based-schema-as-value" aria-label="Permalink to &quot;Approach 1: Convention-based (schema as value) {#Approach-1:-Convention-based-schema-as-value}&quot;">​</a></h3><p>Write schemas as Nickel <strong>values</strong> that describe types, not as actual type annotations:</p><div class="language-nickel vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nickel</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  fields = {</span></span>
<span class="line"><span>    status = { type = &quot;enum&quot;, variants = [&quot;active&quot;, &quot;inactive&quot;] },</span></span>
<span class="line"><span>    name = { type = &quot;string&quot; },</span></span>
<span class="line"><span>    count = { type = &quot;number&quot; },</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Then <code>@nickel_types &quot;schema.ncl&quot;</code> evaluates this with the existing FFI and generates Julia types.</p><ul><li><p><strong>Pro:</strong> Works today with no Rust changes</p></li><li><p><strong>Con:</strong> Redundant — writing schemas-about-schemas instead of using Nickel&#39;s native type syntax</p></li></ul><h3 id="Approach-2:-AST-walking-in-Rust-recommended-if-pursued" tabindex="-1">Approach 2: AST walking in Rust (recommended if pursued) <a class="header-anchor" href="#Approach-2:-AST-walking-in-Rust-recommended-if-pursued" aria-label="Permalink to &quot;Approach 2: AST walking in Rust (recommended if pursued) {#Approach-2:-AST-walking-in-Rust-recommended-if-pursued}&quot;">​</a></h3><p>Add a new Rust FFI function (<code>nickel_extract_types</code>) that parses a <code>.ncl</code> file, walks the AST, and extracts type annotations from record contracts. Returns a structured description of the type schema.</p><p>The Rust side would:</p><ol><li><p>Parse the Nickel source into an AST</p></li><li><p>Walk <code>Term::RecRecord</code> / <code>Term::Record</code> nodes looking for type annotations on fields</p></li><li><p>For each annotated field, extract the <code>TypeF</code> structure</p></li><li><p>Encode <code>TypeF::Enum(rows)</code> → list of variant names/types</p></li><li><p>Encode <code>TypeF::Record(rows)</code> → list of field names/types</p></li><li><p>Return as JSON or binary protocol</p></li></ol><p>The Julia side would:</p><ol><li><p>Call the FFI function to get the type description</p></li><li><p>In a <code>@nickel_types</code> macro, generate <code>struct</code> definitions and enum-like types at compile time</p></li></ol><p>Estimated scope: ~200-400 lines of Rust, plus Julia macro (~100-200 lines).</p><ul><li><p><strong>Pro:</strong> Uses real Nickel type syntax. Elegant.</p></li><li><p><strong>Con:</strong> Couples to <code>nickel-lang-core</code> internals (<code>TypeF</code> enum, AST structure). Could break across crate versions. Medium-to-large effort.</p></li></ul><h3 id="Approach-3:-Nickel-side-reflection" tabindex="-1">Approach 3: Nickel-side reflection <a class="header-anchor" href="#Approach-3:-Nickel-side-reflection" aria-label="Permalink to &quot;Approach 3: Nickel-side reflection {#Approach-3:-Nickel-side-reflection}&quot;">​</a></h3><p>Use Nickel&#39;s runtime to reflect on contracts — e.g., <code>std.record.fields</code> to list record keys, pattern matching to decompose contracts.</p><ul><li><p><strong>Pro:</strong> No Rust changes</p></li><li><p><strong>Con:</strong> Doesn&#39;t work for enum types — Nickel has no runtime mechanism to list the variants of <code>[| &#39;a, &#39;b |]</code>. Dead end for the core use case.</p></li></ul><h2 id="Conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#Conclusion" aria-label="Permalink to &quot;Conclusion {#Conclusion}&quot;">​</a></h2><p><strong>Approach 2 is the only viable path</strong> for using Nickel&#39;s native type syntax, but it&#39;s a significant investment that couples to unstable internal APIs. <strong>Approach 1 is a pragmatic workaround</strong> if the need becomes pressing.</p><p>This is outside the current scope of NickelEval.jl, which focuses on evaluation, not type extraction. If <code>nickel-lang-core</code> ever exposes a public type introspection API, the picture changes significantly.</p><h2 id="Key-Dependencies" tabindex="-1">Key Dependencies <a class="header-anchor" href="#Key-Dependencies" aria-label="Permalink to &quot;Key Dependencies {#Key-Dependencies}&quot;">​</a></h2><ul><li><p><code>nickel-lang-core</code> would need to maintain a stable enough AST/type representation (currently internal)</p></li><li><p>Julia macro system for compile-time type generation (<code>@generated</code> or expression-based macros)</p></li><li><p>Decision on how to map Nickel&#39;s structural types to Julia&#39;s nominal type system (e.g., enum rows → <code>@enum</code> or union of <code>Symbol</code>s)</p></li></ul>`,36)])])}const y=a(s,[["render",o]]);export{h as __pageData,y as default};
